type NestedNumber = number | NestedNumber[];

function flattenTree(input: NestedNumber[]): number[] {
  const result: number[] = [];

  function traverse(node: NestedNumber): void {
    if (typeof node === "number") {
      result.push(node);
    } else {
      for (const child of node) {
        traverse(child);
      }
    }
  }

  for (const item of input) {
    traverse(item);
  }

  return result;
}
